from pathlib import Path
from typing import Iterable, Sequence

import pandas as pd

DEFAULT_CHUNKSIZE = 200_000


def _normalize_symbols(symbols: Iterable[str] | None) -> set[str]:
    if not symbols:
        return set()
    normalized: set[str] = set()
    for value in symbols:
        text = str(value or "").strip().upper()
        if text:
            normalized.add(text)
    return normalized


def _normalize_trade_date_key(value: int | str | None) -> int | None:
    if value is None:
        return None
    text = str(value).strip()
    if not text:
        return None
    digits = "".join(ch for ch in text if ch.isdigit())
    if len(digits) >= 8:
        digits = digits[:8]
    if not digits:
        return None
    try:
        return int(digits)
    except Exception:
        return None


def _empty_frame(usecols: Sequence[str] | None) -> pd.DataFrame:
    if usecols is None:
        return pd.DataFrame()
    return pd.DataFrame(columns=list(usecols))


def iter_a_stock_history_chunks(
    path: Path | str,
    *,
    usecols: Sequence[str] | None = None,
    dtype: dict[str, object] | None = None,
    chunksize: int = DEFAULT_CHUNKSIZE,
    symbols: Iterable[str] | None = None,
    trade_date_min: int | str | None = None,
    trade_date_max: int | str | None = None,
) -> Iterable[pd.DataFrame]:
    csv_path = Path(path)
    if not csv_path.exists():
        raise FileNotFoundError(csv_path)

    symbol_set = _normalize_symbols(symbols)
    min_date = _normalize_trade_date_key(trade_date_min)
    max_date = _normalize_trade_date_key(trade_date_max)

    for chunk in pd.read_csv(csv_path, usecols=usecols, dtype=dtype, chunksize=chunksize):
        if chunk.empty:
            continue

        if "ts_code" in chunk.columns:
            chunk["ts_code"] = chunk["ts_code"].astype(str).str.upper().str.strip()
            if symbol_set:
                chunk = chunk[chunk["ts_code"].isin(symbol_set)].copy()
                if chunk.empty:
                    continue

        if "trade_date" in chunk.columns and (min_date is not None or max_date is not None):
            trade_dates = pd.to_numeric(chunk["trade_date"], errors="coerce").fillna(0).astype(int)
            chunk["trade_date"] = trade_dates
            if min_date is not None:
                chunk = chunk[trade_dates >= min_date].copy()
            if max_date is not None:
                chunk = chunk[chunk["trade_date"] <= max_date].copy()
            if chunk.empty:
                continue

        yield chunk


def read_a_stock_history(
    path: Path | str,
    *,
    usecols: Sequence[str] | None = None,
    dtype: dict[str, object] | None = None,
    chunksize: int = DEFAULT_CHUNKSIZE,
