    trade_date_max: int | str | None = None,
    sort_by: Sequence[str] | None = None,
    dedupe_subset: Sequence[str] | None = None,
) -> pd.DataFrame:
    chunks = list(
        iter_a_stock_history_chunks(
            path,
            usecols=usecols,
            dtype=dtype,
            chunksize=chunksize,
            symbols=symbols,
            trade_date_min=trade_date_min,
            trade_date_max=trade_date_max,
        )
    )
